import { Component, Event, EventEmitter, h, Prop, State, Watch } from '@stencil/core';
import { getStoreQueries, isArray, isDate, isObject, removeQuery, storeQuery } from '@src/utils/mx-utils';
import isEqual from 'lodash.isequal';
import isEmpty from 'lodash.isempty';
import cloneDeep from 'lodash/cloneDeep';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { CalendarType, dateConst, Item } from '@src/utils/mx-utils/calendar-service';
import { QueryPanelTagFields } from './mx-query-panel-tag/mx-query-panel-tag.interface';
import {
  getAllChildrenFromList,
  isMenuItem,
  removeChildInArrayByLabel,
  removeItemsWithEmptyChildren
}
  from '@src/mx-components/menu-item/mx-menu-item/menu-item-utils';
import { isValidGregorianDateString } from '@src/utils/mx-utils/date.ext';

export type queryTypes = 'filter' | 'search';

const QUERY_PANEL_FORM_EVENT_LIST = ['input', 'pickerChange', 'itemChange', 'selectionChanged', 'dateChanged'];
const EXCLUDED_CONTROL_CONTAINER_LIST = ['mx-multi-select'];
const panelWidth: number = 20.625;

type QueryPanelControl = HTMLInputElement | HTMLMxDatePickerElement | HTMLMxTimePickerElement |
  HTMLMxSectionAccordionElement | HTMLMxSingleSelectElement | HTMLMxMultiSelectElement;

@Component({
  tag: 'mx-query-panel',
  styleUrl: 'mx-query-panel.css',
  shadow: false
})
export class MxQueryPanel {
  /** This is used to identify the form element. */
  @Prop() readonly formId!: string;
  /** This property is used to store the type of the query. */
  @Prop() readonly queryType?: queryTypes;
  /** This property is used to store the title of the query. */
  @Prop() readonly queryTitle?: string;
  /** This property is used to show the apply button in the advanced mode of query panel. */
  @Prop() readonly showApplyButton?: boolean;
  /** This is used to determine if the mode is advanced or not. */
  @Prop() readonly advancedMode?: boolean = false;
  /** This property is used to disable the apply button in the modal of query panel. */
  @Prop() readonly disableApplyButton?: boolean;
  /** This property is used to set a custom key in local storage to keep track of persistent storage in the query panel. The key is automatically generated if not provided. */
  @Prop() readonly localStorageKey?: string = this.formId;
  /** This is used to pass initial state for persistent storage when using external storage. **/
  @Prop() readonly queryStore = null;
  /** Determines if panel is open. */
  @Prop() readonly open: boolean = false;
  /** Show skinny panel. */
  @Prop() readonly skinnyPanelVisible: boolean = true;
  /** Alternative header. Applies only if skinnyPanelVisible is false. */
  @Prop() readonly alternativeHeader: string;
  /** Determines if apply button should be enable or disable by default */
  @Prop() readonly applyAlwaysOn?: boolean = false
  /** Determines to show border for  Query panel */
  @Prop() readonly showBorder: boolean = true;

  @Watch('queryStore')
  watchQueryStore(queryStore) {
    this._queryStore = queryStore;
  }

  /** This event is emitted when the user clicks apply button on sliding panel. This is where user clicks to perform search/filter. */
  @Event() applyClickEvent: EventEmitter;
  /** This event is emitted when the user clicks apply button on sliding panel. This is where user clicks to perform search/filter. */
  @Event() saveQuery: EventEmitter<{ queryName: string, formData: any }>;
  /** This event is emitted when the user clicks apply button on sliding panel. This is where user clicks to perform search/filter. */
  @Event() deleteQuery: EventEmitter;
  /** This event is emitted when the user toggles the query panel open and closed. */
  @Event() toggleQueryPanel: EventEmitter;

  @State() _queryStore = this.queryStore;
  @State() isPanelApplyButtonDisabled: boolean;
  @State() isFormValueUnchanged: boolean = true;
  @State() count: number = 0;
  @State() itemSelected: Item;
  @State() isPersistentStorage: boolean = false;
  @State() formData: Object | null;
  @State() panelOpened: boolean;

  @Watch('open')
  onOpenChange(newValue: boolean) {
    this.updateCount();
    this.panelOpened = newValue;
  }

  private readonly formModalName = '_form-modal';

  componentWillLoad() {
    if (isNullOrUndefined(this.queryStore)) {
      const queryStore = getStoreQueries(this.localStorageKey);
      this.initQueryStore(queryStore);
      this.isPersistentStorage = false;
    } else {
      this.initQueryStore(this._queryStore);
      this.isPersistentStorage = true;
    }
  }

  componentDidLoad() {
    if (!this.advancedMode) {
      QUERY_PANEL_FORM_EVENT_LIST.forEach((eventName) => {
        this.documentRef().addEventListener(eventName, () => this.updatePanelApplyDisabled(this.getValues()));
      });
      this.updatePanelApplyDisabled(this.getValues());
    } else {
      this.isPanelApplyButtonDisabled = true;
    }
    this.updateCount();
    this.panelOpened = this.open;
  }

  private initQueryStore(queryStore) {
    this._queryStore = Object.fromEntries(Object.entries(queryStore)
      .map(([key, formData]: [string, any]) => [key, this.isFavouriteItem(formData) ? formData : {
        ...formData,
        serviceData: { favourite: false }
      }]));

    if (!isEmpty(this._queryStore)) {
      // eslint-disable-next-line max-len
      const favouriteItem: any = Object.entries(this._queryStore).find(([_, formData]) => this.isFavouriteItem(formData));
      if (!isNullOrUndefined(favouriteItem)) {
        this.itemSelected = { label: favouriteItem[0], value: favouriteItem[0] };
        this.formData = cloneDeep(favouriteItem[1].formData);
        this.applyClickEvent.emit(this.formData);
      }
    }
  }

  private isFavouriteItem(formData) {
    return !isNullOrUndefined(formData) && formData.serviceData != null && formData.serviceData.favourite;
  }

  private storeData(queryName, queryData) {
    if (this.isPersistentStorage) {
      this.saveQuery.emit({ ...queryData });
    } else {
      storeQuery(this.localStorageKey, queryName, queryData);
    }
  }

  private removeData(queryValue) {
    if (this.isPersistentStorage) {
      this.deleteQuery.emit(queryValue);
    } else {
      removeQuery(this.localStorageKey, queryValue);
    }
  }

  // get the form values in an object
  private getValues() {
    // not using new FormData because we don't get checkbox controls when nothing is checked
    const formData = {};
    this.getControls().forEach((ctrl: QueryPanelControl) => {
      const inputControl: HTMLInputElement = ctrl as HTMLInputElement;
      switch (ctrl.tagName) {
        case QueryPanelTagFields.Input:
          if (inputControl.type === 'checkbox') {
            if (inputControl.checked) {
              if (!formData[inputControl.name]) {
                formData[inputControl.name] = [];
              }
              formData[inputControl.name].push(inputControl.value);
            }
          } else if (inputControl.type === 'radio') {
            if (inputControl.checked) {
              if (!formData[inputControl.name]) {
                formData[inputControl.name] = null;
              }
              formData[inputControl.name] = inputControl.value;
            }
          } else {
            if (!isNullOrUndefinedOrEmptyString(inputControl.value)) {
              formData[inputControl.name] = inputControl.value;
            } else {
              delete formData[inputControl.name];
            }
          }
          break;
        case QueryPanelTagFields.TimePicker:
          // at least period is required
          const timePickerControl: HTMLMxTimePickerElement = ctrl as HTMLMxTimePickerElement;
          if (timePickerControl.value != null && !isNullOrUndefinedOrEmptyString(timePickerControl.value.calYear)) {
            formData[timePickerControl.name] = timePickerControl.value;
          } else {
            delete formData[timePickerControl.name];
          }
          break;
        case QueryPanelTagFields.DatePicker:
          const datePickerControl: HTMLMxDatePickerElement = ctrl as HTMLMxDatePickerElement;
          if (!isNullOrUndefinedOrEmptyString(datePickerControl.value)) {
            const valid = !isDate(datePickerControl.value) &&
              isValidGregorianDateString(datePickerControl.value as string);
            formData[datePickerControl.name] = valid
              ? {
                date:
                    typeof datePickerControl.value === 'string' || datePickerControl.value instanceof Date
                      ? new Date(datePickerControl.value)
                      : null,
                calType: datePickerControl['currentCal']
              }
              : { date: datePickerControl.value, calType: datePickerControl['currentCal'] };
          } else {
            delete formData[datePickerControl.name];
          }
          break;
        case QueryPanelTagFields.MultiSelect:
          const multiSelectControl: HTMLMxMultiSelectElement = ctrl as HTMLMxMultiSelectElement;
          if (!isNullOrUndefined(multiSelectControl.selectedItems) && multiSelectControl.selectedItems.length > 0) {
            formData[multiSelectControl.name] = multiSelectControl.selectedItems;
          }
          break;
        case QueryPanelTagFields.SingleSelect:
          const singleSelectControl: HTMLMxSingleSelectElement = ctrl as HTMLMxSingleSelectElement;
          if (!isNullOrUndefinedOrEmptyString(singleSelectControl.itemSelected)) {
            formData[singleSelectControl.name] = singleSelectControl.itemSelected;
          }
          break;
        default:
          if (!isNullOrUndefinedOrEmptyString(inputControl.value)) {
            formData[inputControl.name] = inputControl.value;
          } else {
            delete formData[inputControl.name];
          }
      }
    });
    this.clearInvalidFormValues(formData);
    return Object.keys(formData).length === 0 ? null : formData;
  }

  private getControls(): Array<QueryPanelControl> {
    const elementsSelectors = ['input:not(mx-time-picker *)', 'textarea', 'mx-input-text-box:not(.mx-input)',
      'mx-time-picker', 'mx-single-select:not(mx-time-picker *)', 'mx-multi-select',
      'mx-section-accordion', 'mx-date-picker'].join(', ');
    const controls: NodeListOf<any> = this.documentRef().querySelectorAll(elementsSelectors);
    return Array.from(controls).filter((control: QueryPanelControl) => {
      let controlIsInsideComponent = true;
      for (const tag of EXCLUDED_CONTROL_CONTAINER_LIST) {
        controlIsInsideComponent = controlIsInsideComponent &&
          this.controlIsInsideComponent(control, tag);
      }
      return !controlIsInsideComponent;
    });
  }

  private controlIsInsideComponent(control: QueryPanelControl, componentTagName: string): boolean {
    const controlIsAComponent: boolean = control.tagName.toLowerCase() === componentTagName.toLowerCase();
    if (controlIsAComponent) {
      return false;
    }

    return control.closest(componentTagName) != null;
  }

  private getValueForDatepicker(dateValue: string | Date | undefined): Date {
    if (typeof dateValue === 'string' && isValidGregorianDateString(dateValue)) {
      return new Date(dateValue);
    }
    return new Date(dateValue);
  }

  // set the form values from an object i.e. input ={"field1": "name", "field2": "user","field3": ["Category Manager","Category Manager - Assistant CM"],"field4": "radio2"}
  // in setValues we are checking the input types as we can't directly update the checkboxes and radio controls same as textboxes
  private setValues(formData) {
    this.getControls().forEach((ctrl: QueryPanelControl) => {
      const inputControl: HTMLInputElement = ctrl as HTMLInputElement;
      switch (ctrl.tagName) {
        case QueryPanelTagFields.Input:
          if (inputControl.type === 'checkbox') {
            inputControl.checked = !formData[inputControl.name] ?
              false :
              formData[inputControl.name].includes(inputControl.value);
          } else if (inputControl.type === 'radio') {
            inputControl.checked = formData[inputControl.name] === inputControl.value;
          } else {
            inputControl.value = formData[inputControl.name] ? formData[inputControl.name] : '';
          }
          break;
        case QueryPanelTagFields.TimePicker:
          const timePickerControl: HTMLMxTimePickerElement = ctrl as HTMLMxTimePickerElement;
          const value = formData[timePickerControl.name];
          if (!isNullOrUndefinedOrEmptyString(value)) {
            const { quarter, week, calYear, period, calType } = value;
            timePickerControl.timePickerData = { year: calYear, quarter, period, week };
            timePickerControl.calType = calType;
          }
          break;
        case QueryPanelTagFields.DatePicker:
          const datePickerElement: HTMLMxDatePickerElement = ctrl as HTMLMxDatePickerElement;
          if (!isNullOrUndefinedOrEmptyString(formData[datePickerElement.name])) {
            const dateValue = this.getValueForDatepicker(formData[datePickerElement.name]?.date);
            datePickerElement.selectedCal = formData[datePickerElement.name]?.calType;
            datePickerElement.value = dateValue;
          }
          break;
        case QueryPanelTagFields.MultiSelect:
          this.updateMultiSelect((ctrl as HTMLMxMultiSelectElement).name);
          break;
        case QueryPanelTagFields.SingleSelect:
          this.updateSingleSelect((ctrl as HTMLMxSingleSelectElement).name);
          break;
        default:
          inputControl.value = formData[inputControl.name] ? formData[inputControl.name] : '';
      }
    });
  }

  private documentRef() {
    if (isNullOrUndefinedOrEmptyString(this.formId)) {
      return document;
    } else {
      return document.forms[this.formId] || document;
    }
  };

  private updateSingleSelect(fieldName: string) {
    const singleSelectRef: HTMLMxSingleSelectElement =
      this.documentRef().querySelector(`mx-single-select[name="${fieldName}"]`);
    if (!isNullOrUndefined(singleSelectRef) && !isNullOrUndefined(this.formData[fieldName])) {
      singleSelectRef.itemSelected = this.formData[fieldName].children ?
        this.formData[fieldName].children[0] :
        this.formData[fieldName] ? this.formData[fieldName] : '';
    }
  }

  private updateMultiSelect(fieldName: string) {
    const multiSelectRef: HTMLMxMultiSelectElement =
      this.documentRef().querySelector(`mx-multi-select[name="${fieldName}"]`);
    if (!isNullOrUndefined(multiSelectRef) && !isNullOrUndefined(this.formData[fieldName])) {
      multiSelectRef.selectedItems = [...this.formData[fieldName]];
    }
  }

  private removeEmptyField(field: QueryPanelTagFields) {
    if (isArray(this.formData[field]) && this.formData[field].length === 0) {
      delete this.formData[field];
    }
  }

  private readonly deleteValue = (event: CustomEvent) => {
    const { field, value } = event.detail;
    const singleSelectRef = this.documentRef().querySelector(`mx-single-select[name="${field}"]`);
    const multiSelectRef = this.documentRef().querySelector(`mx-multi-select[name="${field}"]`);
    if (!isNullOrUndefined(singleSelectRef)) {
      singleSelectRef.clearSelection();
      delete this.formData[field];
      this.formData = { ...this.formData };
    } else if (!isNullOrUndefined(multiSelectRef)) {
      const isArrayOfValues = typeof this.formData[field][0] === 'string';
      if (isArrayOfValues) {
        const index = this.formData[field].indexOf(value);
        this.formData[field].splice(index, 1);
      }
      removeChildInArrayByLabel(this.formData[field], value);
      this.formData[field] = [...removeItemsWithEmptyChildren(this.formData[field])];
      this.formData = { ...this.formData };
    } else if (isArray(this.formData[field])) {
      const i = this.formData[field].indexOf(value);
      const cloneFormArray = [...this.formData[field]];
      cloneFormArray.splice(i, 1);
      this.formData = { ...this.formData, [field]: [...cloneFormArray] };
    } else if (isDate(this.formData[field]?.date)) {
      const newFormData = {};
      Object.keys(this.formData).forEach((k) => {
        if (k !== field) {
          newFormData[k] = this.formData[k];
        }
      });
      this.resetDatePicker();
      this.formData = { ...newFormData };
    } else if (isObject(this.formData[field])) {
      const newFormData = {};
      Object.keys(this.formData).forEach((k) => {
        if (k !== field) {
          newFormData[k] = this.formData[k];
        }
      });
      this.resetTimePicker();
      this.formData = { ...newFormData };
    } else {
      const newFormData = {};
      Object.keys(this.formData).forEach((k) => {
        if (k !== field) {
          newFormData[k] = this.formData[k];
        }
      });
      this.formData = { ...newFormData };
    }
    this.updatePanelApplyDisabled(this.formData);

    if (this.isPanelApplyButtonDisabled)
      this.applyClickEvent.emit(this.formData);

    this.isFormValueUnchanged = false; // this flag identify that the form value is changed when deleted an item from the form
    // We need to sanitize our formData and delete an array if it is empty.
    // The reason for this is that we could've deleted the last item of the array, but the array still exists.
    // This will result in the field label still being visible for the tag, but no tag will be displayed.
    // This is not intended behavior.
    this.removeEmptyField(field);
  };

  private resetForm() {
    this.getControls().forEach((ctrl: QueryPanelControl) => {
      const inputControl: HTMLInputElement = ctrl as HTMLInputElement;
      switch (ctrl.tagName) {
        case QueryPanelTagFields.Input:
          if (inputControl.type === 'checkbox' || inputControl.type === 'radio') {
            inputControl.checked = false;
          } else {
            inputControl.value = '';
          }
          break;
        case QueryPanelTagFields.TimePicker:
          this.resetTimePicker();
          (ctrl as HTMLMxTimePickerElement).calType = 'fiscal';
          break;
        case QueryPanelTagFields.DatePicker:
          this.resetDatePicker();
          (ctrl as HTMLMxDatePickerElement).selectedCal = 'gregorian';
          break;
        case QueryPanelTagFields.MultiSelect:
          (ctrl as HTMLMxMultiSelectElement).selectedItems = [];
          break;
        case QueryPanelTagFields.SingleSelect:
          (ctrl as HTMLMxSingleSelectElement).clearSelection();
          break;
        case QueryPanelTagFields.SectionAccordion:
          (ctrl as HTMLMxSectionAccordionElement).expanded = false;
          break;
        default:
          inputControl.value = '';
      }
    });
  }

  private readonly resetTimePicker = () => {
    this.documentRef().querySelectorAll(`mx-time-picker`).forEach((ctrl) => ctrl.timePickerData = {
      year: -1,
      quarter: -1,
      period: -1,
      week: -1
    });
  };

  private readonly resetDatePicker = () => {
    this.documentRef().querySelectorAll(`mx-date-picker`).forEach((ctrl) => ctrl.reset());
  }

  // Reset the form when we click on clear link
  private readonly clearAll = (e: MouseEvent) => {
    e?.preventDefault();
    this.resetForm();
    this.formData = {};
    this.updatePanelApplyDisabled(this.formData);
    this.isFormValueUnchanged = false;
    this.applyClickEvent.emit(this.formData);
  };

  private readonly showModal = async () => {
    const modal: HTMLMxModalElement = document.querySelector(`mx-modal#${this.localStorageKey}${this.formModalName}`);
    if (!isNullOrUndefined(this.formData) && Object.keys(this.formData).length > 0) {
      this.setValues(this.formData);
    }
    await modal.createModal();
  };

  // Had to add a separate function for this because of rendering issues with mx-input-text-box.
  // It was not rendering the value properly when we were resetting the form as soon as we opened it,
  // so we are resetting it when we close it instead. This change is just a timing difference in practice.
  private readonly onModalCloseClick = () => {
    // Reset the values to clear out any unsaved changes.

    if ((!isNullOrUndefined(this.formData) && Object.keys(this.formData).length > 0) ||
      QueryPanelTagFields.SectionAccordion) {
      this.resetForm();
    }
  };

  // To emit formData by clicking apply button on sliding panel
  private readonly onApplyClick = () => {
    if (this.advancedMode && !isNullOrUndefined(this.formData) && Object.keys(this.formData).length > 0) {
      this.applyClickEvent.emit(this.formData);
    } else {
      this.applyClickEvent.emit(this.getValues());
    }
  };

  /** Multi-select kds-checkboxes are included in the form values as separate items when
   the "Apply" button is clicked and the form is still opened. This gets added to our object with
   an empty name. We don't need this as it adds a tag with "on" per checkbox. */
  private clearInvalidFormValues(formValues: Object) {
    if (!isNullOrUndefined(formValues) && !isNullOrUndefined(formValues[''])) {
      delete formValues[''];
    }
  }

  private updatePanelApplyDisabled(formData) {
    const hasValidFormData = (formData) => {
      return formData != null && Object.keys(formData).some((key: string) => {
        if (isArray(formData[key])) {
          return formData[key].length > 0;
        } else if (isObject(formData[key])) {
          return formData[key]?.children?.length > 0 ||
            !isNullOrUndefinedOrEmptyString(formData[key].calYear) ||
            !isNullOrUndefined(formData[key].date);
        } else {
          return !isNullOrUndefinedOrEmptyString(formData[key]);
        }
      });
    };

    // Update the class property based on the computed boolean value
    this.isPanelApplyButtonDisabled = this.advancedMode
      ? !hasValidFormData(formData) // In advanced mode, apply button depends only on form data
      : (!this.applyAlwaysOn && !hasValidFormData(formData)); // Non-advanced mode considers applyAlwaysOn
  }


  // Triggering this method by clicking apply button on mx-modal
  private readonly onModalApplyClick = async () => {
    const formValues = this.getValues();
    this.isFormValueUnchanged = isEqual(this.formData, formValues);

    // Return an empty Object here in the event that there are no items.
    // This matches resetting, or hitting clear all, or removing all tags.
    this.formData = formValues == null ? {} : formValues;
    const modal: HTMLMxModalElement = document.querySelector(`mx-modal#${this.localStorageKey}${this.formModalName}`);
    await modal.dismissModal();
    this.applyClickEvent.emit(this.formData);
    this.updatePanelApplyDisabled(this.formData);
  };

  private readonly onModalResetClick = () => {
    this.resetForm();
  };

  private readonly updateCount = () => {
    const formData = this.advancedMode ? this.formData : this.getValues();
    this.count = 0;
    if (formData == null) {
      return;
    }
    for (const value of Object.values(formData)) { // Loop through the selected values and get a count of valid values
      const isArrayOfMenuItems = isArray(value) && value.length > 0 && isMenuItem(value[0]);
      if (!isNullOrUndefinedOrEmptyString(value) && !isArrayOfMenuItems) {
        this.count += Array.isArray(value) && isArray(value) && !isArrayOfMenuItems ? value.length : 1;
      }
      if (isArrayOfMenuItems) {
        const childrenCount = getAllChildrenFromList(value).length;
        this.count += childrenCount;
      }
    }
  };

  private readonly toggleSlidingPanel = (e: CustomEvent) => {
    this.toggleQueryPanel.emit(e.detail.open);
    this.updateCount();
    this.panelOpened = e.detail.open;
    this.getControls().forEach((ctrl: QueryPanelControl) => {
      if (QueryPanelTagFields.SectionAccordion) {
        (ctrl as HTMLMxSectionAccordionElement).expanded = false;
      }
    });
  };

  private readonly saveQueryData = (queryEvent: CustomEvent) => {
    const queryName = queryEvent.detail.name;
    const queryData = {
      queryName: queryName,
      formData: this.formData,
      serviceData: {
        favourite: queryEvent.detail.favourite
      }
    };
    // We need an immutable copy of this data, as otherwise we are continuously mutating it without being
    // aware of the side effects this brings along. Mainly, if we use mutation, when we go to reset the filter, it will
    // simply "revert" back to itself. i.e. it will not revert to the initial query store, but rather the
    // exact same value it already had. This is not our intended behavior.
    this._queryStore = cloneDeep({ ...this._queryStore, ...{ [queryName]: queryData } });
    Object.keys(this._queryStore).forEach((key) => {
      const queryStoreKey = this._queryStore[key];
      const queryEventFavourite = queryEvent.detail.favourite;
      const isQueryNameMatch = queryName === key;
      if (isQueryNameMatch) {
        queryStoreKey.serviceData.favourite = queryEventFavourite; // not sure why this is needed, but kept as per code
      } else {
        queryStoreKey.serviceData.favourite = !queryEventFavourite && queryStoreKey.serviceData.favourite;
      }
      this.storeData(key, isQueryNameMatch ? queryData : this._queryStore[key]); // why do we store all data again
    });
    this.itemSelected = { label: queryName, value: queryName };
    this.isFormValueUnchanged = true;
  };

  private readonly deleteQueryData = (queryEvent: CustomEvent) => {
    const queryValue: any = queryEvent.detail.value;
    this.removeData(queryValue);
    delete this._queryStore[queryValue];
    this._queryStore = { ...this._queryStore };
    if (this.itemSelected?.value === queryValue) {
      this.itemSelected = null;
    }
    this.isFormValueUnchanged = true;
    if (this.itemSelected == null) {
      this.resetForm();
      this.formData = {};
    }
  };

  private readonly favouriteQuery = (queryEvent: CustomEvent) => {
    const queryName = queryEvent.detail;
    if (this._queryStore.hasOwnProperty(queryName)) {
      Object.keys(this._queryStore).forEach((key) => {
        this._queryStore[key].serviceData = {
          favourite: queryName === key ? !this._queryStore[queryName].serviceData?.favourite : false
        };
        this.storeData(key, this._queryStore[key]);
      });
    }
    this._queryStore = { ...this._queryStore };
  };

  private readonly resetQueryStore = (event: CustomEvent<Item>) => {
    const queryName = (event.detail.value as string);
    this.formData = cloneDeep(this._queryStore[queryName].formData);
    this.resetForm();
    this.isPanelApplyButtonDisabled = isNullOrUndefined(this.applyAlwaysOn) ? true : !this.applyAlwaysOn;;
    this.isFormValueUnchanged = true;
    this.applyClickEvent.emit(this.formData);
  };

  private readonly formatAdFiscalDate = (control: HTMLMxDatePickerElement, field) => {
    const isFiscal: boolean = this.formData[field]?.calType === CalendarType.FISCAL;
    const dateOffset: number = isFiscal ? 0 : 3;
    const hideDays: boolean = (isFiscal && control.hideFiscalDays) ||
      (!isFiscal && control.hideAdDays);
    const prefix = isFiscal ? 'fiscal ' : 'ad ';

    const formattedPeriod =
      this.formData[field]?.calType === CalendarType.FISCAL || this.formData[field]?.calType === CalendarType.AD
        ? dateConst.formatPeriodDate(
          this.formData[field]?.date,
          hideDays,
          control.showFiscalWeek,
          dateOffset
        )
        : this.formData[field]?.date;

    return control.hasPeriodMask
      ? `${this.formData[field]?.calType !== CalendarType.GREGORIAN ? prefix : ''}${formattedPeriod}`
      : this.formData[field]?.date;
  };

  private readonly setDataFromQueryStore = (queryName: string) => {
    const data = cloneDeep(this._queryStore[queryName].formData);

    return Object.keys(data).reduce((arr: any, field: any) => {
      if (data[field].date) {
        arr[field] = { date: new Date(data[field].date), calType: data[field].calType };
      } else {
        arr[field] = data[field];
      }
      return arr;
    }, {});
  }

  private readonly changeQueryStore = (queryEvent: CustomEvent) => {
    const item = queryEvent.detail;
    const queryName = item.value;
    if (queryName == null) {
      this.resetForm();
      this.formData = {};
      this.isPanelApplyButtonDisabled = isNullOrUndefined(this.applyAlwaysOn) ? true : !this.applyAlwaysOn;;
      if (this.itemSelected != null) {
        this.applyClickEvent.emit(null);
      }
      this.itemSelected = null;
      return;
    }
    this.formData = this.setDataFromQueryStore(queryName);
    this.isPanelApplyButtonDisabled = isNullOrUndefined(this.applyAlwaysOn) ? true : !this.applyAlwaysOn;;
    this.applyClickEvent.emit(this.formData);
    this.itemSelected = item;
    this.isFormValueUnchanged = true;
  };

  render() {
    const panelTitle = !isNullOrUndefinedOrEmptyString(this.queryTitle)
      ? this.queryTitle
      : this.queryType == 'filter'
        ? 'Filter'
        : 'Search';

    const closedAndNotSkinny: boolean = !this.skinnyPanelVisible && !this.panelOpened;

    return (
      <div
        class={{
          'mx-SlidingPanelWrapper h-full min-h-full mx-query-panel-wrapper': true,
          'mx-query-panel-wrapper__no-skinny-panel': !this.skinnyPanelVisible
        }}
        style={{ width: !this.skinnyPanelVisible ? `${panelWidth}rem` : 'fit-content' }}>
        {
          this.skinnyPanelVisible ?
            null :
            <div class='mx-query-panel-alternative-header' title={this.alternativeHeader || panelTitle}>
              {this.alternativeHeader || panelTitle}
            </div>
        }
        <mx-sliding-panel show-border={this.showBorder}
          class={{
            'bg-primary mx-query-sliding-panel rounded-8  h-full min-h-full': true,
            'border border-neutral-least-subtle box-content': this.showBorder,
            'mx-query-sliding-panel__no-skinny-header': !this.skinnyPanelVisible,
            'mx-query-sliding-panel__no-skinny-header-closed': closedAndNotSkinny
          }}
          header-css-class={[
            'border-neutral-less-subtle',
            'mx-query-panel-header',
            closedAndNotSkinny ? 'mx-query-panel-header-closed' : ''
          ].join(' ')}
          header-button-css-class={[
            'mx-query-panel-header-button',
            closedAndNotSkinny ? 'mx-query-panel-header-button-closed' : ''
          ].join(' ')}
          panelTitle={panelTitle}
          align='left'
          has-background={this.skinnyPanelVisible.toString()}
          panelWidth={panelWidth}
          open={this.panelOpened}
          icon={this.queryType == 'filter' ? 'kds-icon-filters' : 'kds-icon-search'}
          badgeValue={this.count}
          badge-label='selected values'
          closeIcon={!this.skinnyPanelVisible ? 'kds-icon-close' : 'kds-icon-caret-left'}
          onSlidingPanelToggled={this.toggleSlidingPanel}>
          {this.advancedMode && (
            <mx-query-store
              isFormValueUnchanged={this.isFormValueUnchanged}
              modal-id-prefix={this.localStorageKey}
              onChangeQueryStore={this.changeQueryStore}
              queryStore={this._queryStore}
              itemSelected={this.itemSelected}
              onSaveQueryStore={this.saveQueryData}
              onRemoveQueryStore={this.deleteQueryData}
              onFavouriteQueryStore={this.favouriteQuery}
              onResetQueryStore={this.resetQueryStore}>
            </mx-query-store>
          )}

          <div class='mx-queryPanel-content bg-primary'>
            <div class='mx-queryPanel-content-header'>
              {this.advancedMode && (
                <kds-button
                  kind='dominant'
                  palette='brand'
                  variant='border'
                  compact={true}
                  class='float-left'
                  id='modal-trigger'
                  onClick={this.showModal}>
                  Modify
                </kds-button>
              )}
              <kds-link onClick={(e: MouseEvent) => this.clearAll(e)} size='m' class='float-right' tabindex='0'>
                Clear All
              </kds-link>
            </div>
            {!this.advancedMode && (
              <form action='' method='get' id={this.formId}>
                <slot />
              </form>
            )}
            {!isNullOrUndefined(this.formData) && Object.keys(this.formData).length > 0 && (
              <div class='mt-48'>
                {Object.keys(this.formData).map((field: any) => {
                  const control: QueryPanelControl = this.getControls()
                    .find((ctrl: HTMLInputElement) => ctrl.name === field);
                  if (control != null && control.tagName === QueryPanelTagFields.DatePicker) {
                    const item = this.formatAdFiscalDate(control as HTMLMxDatePickerElement, field);
                    return <mx-query-panel-tag
                      item={item}
                      field={field}
                      onDeleteValue={this.deleteValue} />;
                  } else {
                    return <mx-query-panel-tag
                      item={this.formData[field]}
                      field={field}
                      onDeleteValue={this.deleteValue} />;
                  }
                })}
              </div>
            )}
          </div>
          {
            // We may want to show a blank footer in this case?
            this.showApplyButton && (
              <footer class='p-16 bg-primary pin-b sticky border-t mx-queryPanel-footer border-neutral-less-subtle'>
                <kds-button
                  disabled={this.isPanelApplyButtonDisabled}
                  kind='dominant'
                  palette='brand'
                  class='w-full'
                  buttonClass='w-full'
                  onClick={this.onApplyClick}>
                  Apply
                </kds-button>
              </footer>
            )}
        </mx-sliding-panel>
        {this.advancedMode && (
          <mx-modal
            id={this.localStorageKey + this.formModalName}
            close-modal-on-overlay-click='true'
            size='large'
            headercontent='Header'
            footer-primary-button-kind='primary'
            footer-primary-button-text='Apply'
            is-active-secondary-button='true'
            footer-secondary-button-text='Cancel'
            is-active-ternary-button='true'
            footer-ternary-button-text='Reset'
            onApplyClick={this.onModalApplyClick}
            onResetClick={this.onModalResetClick}
            onModalClose={this.onModalCloseClick}
            is-active-primary-button={this.disableApplyButton}>
            <form action='' method='get' id={this.formId}>
              <slot />
            </form>
          </mx-modal>
        )}
      </div>
    );
  }
}
